import{promises as e}from"node:fs";import{MarketTrendSchema as r,ReaderPreferenceSchema as c}from"./types.js";export class FileMarketSource{name="file";config;constructor(a){this.config={watch:a.watch??!0,...a}}async fetchTrends(){const a=await this.readFile();if(!a)return[];const t=r.array().safeParse(a.trends);return t.success?t.data:[]}async fetchPreferences(){const a=await this.readFile();if(!a)return[];const t=c.array().safeParse(a.preferences);return t.success?t.data:[]}async isAvailable(){try{return await e.access(this.config.filePath),!0}catch{if(this.config.fallbackPath)try{return await e.access(this.config.fallbackPath),!0}catch{return!1}return!1}}async readFile(){const a=await this.readRaw();if(a===null)return null;try{return JSON.parse(a)}catch{return null}}async readRaw(){try{return await e.readFile(this.config.filePath,"utf8")}catch{}if(this.config.fallbackPath)try{return await e.readFile(this.config.fallbackPath,"utf8")}catch{}return null}}
